{
  "name": "OID4VP Basic",
  "description": "Minimal OpenID4VP connection - extracts all VC claims (no filtering)",
  "templateId": "digital-credentials",
  "federatedAuthenticators": {
    "defaultAuthenticatorId": "T3BlbklENFZQQXV0aGVudGljYXRvcg",
    "authenticators": [
      {
        "authenticatorId": "T3BlbklENFZQQXV0aGVudGljYXRvcg",
        "isEnabled": true,
        "properties": [
          { "key": "presentationDefinitionId", "value": "{{presentation_definition_id}}" },
          { "key": "responseMode", "value": "direct_post" },
          { "key": "timeout", "value": "300" }
        ]
      }
    ]
  }
}

{
  "name": "OID4VP With Claims",
  "description": "Connection with claim mappings - validates and filters VC claims",
  "templateId": "digital-credentials",
  "federatedAuthenticators": {
    "defaultAuthenticatorId": "T3BlbklENFZQQXV0aGVudGljYXRvcg",
    "authenticators": [
      {
        "authenticatorId": "T3BlbklENFZQQXV0aGVudGljYXRvcg",
        "isEnabled": true,
        "properties": [
          { "key": "presentationDefinitionId", "value": "{{presentation_definition_id}}" },
          { "key": "responseMode", "value": "direct_post" },
          { "key": "timeout", "value": "300" },
          { "key": "subjectClaim", "value": "email" }
        ]
      }
    ]
  },
  "claims": {
    "userIdClaim": { "uri": "http://wso2.org/claims/emailaddress" },
    "mappings": [
      { "idpClaim": "email", "localClaim": { "uri": "http://wso2.org/claims/emailaddress" } },
      { "idpClaim": "first_name", "localClaim": { "uri": "http://wso2.org/claims/givenname" } },
      { "idpClaim": "last_name", "localClaim": { "uri": "http://wso2.org/claims/lastname" } }
    ],
    "provisioningClaims": []
  }
}

{
  "name": "OID4VP Degree Verifier",
  "description": "Inline PD with nested claim paths (e.g. degree.type)",
  "templateId": "digital-credentials",
  "federatedAuthenticators": {
    "defaultAuthenticatorId": "T3BlbklENFZQQXV0aGVudGljYXRvcg",
    "authenticators": [
      {
        "authenticatorId": "T3BlbklENFZQQXV0aGVudGljYXRvcg",
        "isEnabled": true,
        "properties": [
          { "key": "responseMode", "value": "direct_post" },
          { "key": "timeout", "value": "600" },
          { "key": "subjectClaim", "value": "credentialSubject.id" },
          { "key": "presentationDefinition", "value": "{\"id\":\"degree-verification\",\"input_descriptors\":[{\"id\":\"degree_vc\",\"name\":\"University Degree\",\"purpose\":\"Verify university degree\",\"constraints\":{\"fields\":[{\"path\":[\"$.type\"],\"filter\":{\"type\":\"array\",\"contains\":{\"const\":\"UniversityDegreeCredential\"}}},{\"path\":[\"$.credentialSubject.degree.type\"]},{\"path\":[\"$.credentialSubject.degree.name\"]},{\"path\":[\"$.credentialSubject.alumniOf\"]}]}}]}" }
        ]
      }
    ]
  },
  "claims": {
    "userIdClaim": { "uri": "http://wso2.org/claims/username" },
    "mappings": [
      { "idpClaim": "degree.type", "localClaim": { "uri": "http://wso2.org/claims/organization" } },
      { "idpClaim": "degree.name", "localClaim": { "uri": "http://wso2.org/claims/title" } },
      { "idpClaim": "alumniOf", "localClaim": { "uri": "http://wso2.org/claims/department" } },
      { "idpClaim": "email", "localClaim": { "uri": "http://wso2.org/claims/emailaddress" } }
    ],
    "provisioningClaims": []
  }
}

{
  "name": "OID4VP Full Config",
  "description": "All authenticator properties + claims + role mappings",
  "templateId": "digital-credentials",
  "federatedAuthenticators": {
    "defaultAuthenticatorId": "T3BlbklENFZQQXV0aGVudGljYXRvcg",
    "authenticators": [
      {
        "authenticatorId": "T3BlbklENFZQQXV0aGVudGljYXRvcg",
        "isEnabled": true,
        "properties": [
          { "key": "clientId", "value": "custom-verifier-client" },
          { "key": "presentationDefinitionId", "value": "{{presentation_definition_id}}" },
          { "key": "responseMode", "value": "direct_post" },
          { "key": "timeout", "value": "120" },
          { "key": "subjectClaim", "value": "email" }
        ]
      }
    ]
  },
  "claims": {
    "userIdClaim": { "uri": "http://wso2.org/claims/emailaddress" },
    "roleClaim": { "uri": "http://wso2.org/claims/role" },
    "mappings": [
      { "idpClaim": "email", "localClaim": { "uri": "http://wso2.org/claims/emailaddress" } },
      { "idpClaim": "first_name", "localClaim": { "uri": "http://wso2.org/claims/givenname" } },
      { "idpClaim": "last_name", "localClaim": { "uri": "http://wso2.org/claims/lastname" } },
      { "idpClaim": "phone", "localClaim": { "uri": "http://wso2.org/claims/mobile" } },
      { "idpClaim": "country", "localClaim": { "uri": "http://wso2.org/claims/country" } },
      { "idpClaim": "organization", "localClaim": { "uri": "http://wso2.org/claims/organization" } },
      { "idpClaim": "role", "localClaim": { "uri": "http://wso2.org/claims/role" } }
    ],
    "provisioningClaims": [
      { "claim": { "uri": "http://wso2.org/claims/emailaddress" }, "defaultValue": "" },
      { "claim": { "uri": "http://wso2.org/claims/givenname" }, "defaultValue": "" }
    ]
  },
  "roles": {
    "mappings": [
      { "idpRole": "admin", "localRole": "Internal/admin" },
      { "idpRole": "user", "localRole": "Internal/everyone" }
    ]
  }
}

{
  "name": "OID4VP Test App",
  "description": "Test application for OpenID4VP flow",
  "inboundProtocolConfiguration": {
    "oidc": {
      "grantTypes": ["authorization_code"],
      "callbackURLs": ["https://localhost:3000/callback"],
      "publicClient": false
    }
  },
  "authenticationSequence": {
    "type": "USER_DEFINED",
    "steps": [
      {
        "id": 1,
        "options": [
          {
            "idp": "OpenID4VP Verifier",
            "authenticator": "OpenID4VPAuthenticator"
          }
        ]
      }
    ]
  }
}

{
  "name": "University Degree Verification",
  "description": "Verifies a university degree credential",
  "definitionJson": "{\"id\":\"university-degree-verification\",\"input_descriptors\":[{\"id\":\"degree_credential\",\"name\":\"University Degree\",\"purpose\":\"We need to verify your university degree\",\"constraints\":{\"fields\":[{\"path\":[\"$.type\"],\"filter\":{\"type\":\"array\",\"contains\":{\"const\":\"UniversityDegreeCredential\"}}},{\"path\":[\"$.credentialSubject.degree.type\"]},{\"path\":[\"$.credentialSubject.degree.name\"]}]}}]}"
}

{
  "name": "University Degree Verification (Updated)",
  "description": "Updated - Verifies a university degree credential with alumni status",
  "definitionJson": "{\"id\":\"university-degree-verification\",\"input_descriptors\":[{\"id\":\"degree_credential\",\"name\":\"University Degree\",\"purpose\":\"We need to verify your university degree\",\"constraints\":{\"fields\":[{\"path\":[\"$.type\"],\"filter\":{\"type\":\"array\",\"contains\":{\"const\":\"UniversityDegreeCredential\"}}},{\"path\":[\"$.credentialSubject.degree.type\"]},{\"path\":[\"$.credentialSubject.degree.name\"]},{\"path\":[\"$.credentialSubject.alumniOf\"]}]}}]}"
}

{
  "clientId": "openid4vp-verifier",
  "presentationDefinition": {
    "id": "inline-degree-check",
    "input_descriptors": [
      {
        "id": "degree_credential",
        "name": "University Degree",
        "purpose": "We need to verify your university degree",
        "constraints": {
          "fields": [
            {
              "path": ["$.type"],
              "filter": {
                "type": "array",
                "contains": {
                  "const": "UniversityDegreeCredential"
                }
              }
            },
            {
              "path": ["$.credentialSubject.degree.type"]
            }
          ]
        }
      }
    ]
  },
  "responseMode": "direct_post",
  "didMethod": "did:web",
  "nonce": "test-nonce-inline-67890"
}
